def adapt(a_payload):
    from decimal import Decimal, ROUND_HALF_UP

    # Currencies with no minor units (value is already in major units).
    zero_decimal_currencies = {
        "BIF", "CLP", "DJF", "GNF", "ISK", "JPY", "KMF", "KRW",
        "PYG", "RWF", "UGX", "VND", "VUV", "XAF", "XOF", "XPF",
    }
    # Currencies with three minor-unit digits.
    three_decimal_currencies = {
        "BHD", "IQD", "JOD", "KWD", "LYD", "OMR", "TND",
    }

    raw = a_payload.get("amount")
    currency = a_payload.get("currency")

    if currency is None:
        raise ValueError("Missing currency")
    currency = str(currency).strip().upper()

    if raw is None:
        raise ValueError("Missing amount")

    # Work with Decimal to avoid float rounding artifacts.
    amount = Decimal(str(raw))

    if currency in zero_decimal_currencies:
        exponent = 0
    elif currency in three_decimal_currencies:
        exponent = 3
    else:
        exponent = 2

    divisor = Decimal(10) ** exponent
    major = amount / divisor

    # Normalize to the currency's natural number of decimal places.
    quant = Decimal(1) if exponent == 0 else Decimal(1).scaleb(-exponent)
    major = major.quantize(quant, rounding=ROUND_HALF_UP)

    return {"value": float(major), "currency": currency}

