def adapt(a_payload):
    from decimal import Decimal, ROUND_HALF_UP

    # Currencies with no minor units (amount is already in major units).
    ZERO_DECIMAL = {
        "JPY", "KRW", "VND", "CLP", "PYG", "ISK", "HUF", "TWD",
        "UGX", "RWF", "XOF", "XAF", "XPF", "GNF", "KMF", "DJF",
        "BIF", "VUV", "MGA",
    }
    # Currencies with three minor-unit digits.
    THREE_DECIMAL = {
        "BHD", "IQD", "JOD", "KWD", "LYD", "OMR", "TND",
    }

    if not isinstance(a_payload, dict):
        raise ValueError("payload must be a dict")

