    if not isinstance(currency, str) or not currency.strip():
        raise ValueError("missing or invalid currency")
    currency = currency.strip().upper()

    raw_amount = a_payload.get("amount")
    if raw_amount is None:
        raise ValueError("missing amount")

    # Interpret the amount. It is assumed to be an integer count of the
    # currency's minor units (the common convention illustrated by the
    # sample: 2599 EUR -> 25.99). If it is already a float/decimal string
    # we treat it as-is only when it clearly isn't an integer minor amount.
    if currency in ZERO_DECIMAL:
        exponent = 0
    elif currency in THREE_DECIMAL:
        exponent = 3
    else:
        exponent = 2

    try:
        amount_dec = Decimal(str(raw_amount))
    except Exception:
        raise ValueError("invalid amount")

    if exponent == 0:
        major = amount_dec
    else:
        major = amount_dec / (Decimal(10) ** exponent)

    quant = Decimal(1) if exponent == 0 else Decimal(1).scaleb(-exponent)
    major = major.quantize(quant, rounding=ROUND_HALF_UP)

    return {"value": float(major), "currency": currency}

