def adapt(a_payload):
    raw = a_payload.get("phone")
    if raw is None:
        raise ValueError("missing 'phone' in payload")

    # Normalize to a string and strip common formatting characters.
    s = str(raw).strip()
    for ch in (" ", "-", "(", ")", ".", "/", "\t"):
        s = s.replace(ch, "")

    # Handle international access prefixes:
    #   "00" is the common international dialing prefix -> replace with "+"
    if s.startswith("+"):
        digits = s[1:]
        if not digits.isdigit():
            raise ValueError("invalid phone number: %r" % raw)
        e164 = "+" + digits
    elif s.startswith("00"):
        digits = s[2:]
        if not digits.isdigit():
            raise ValueError("invalid phone number: %r" % raw)
        e164 = "+" + digits
    else:
        # No country code / prefix present. The System-A sample uses a
        # national number without a leading country code. We must not
        # assume the country, but E.164 requires one. We CANNOT reliably
        # derive it from the payload alone, so we refuse to misroute and
        # fail loudly rather than silently prepend a wrong country code.
        if not s.isdigit():
            raise ValueError("invalid phone number: %r" % raw)
        raise ValueError(
            "phone number %r lacks a country code and cannot be safely "
            "converted to E.164" % raw
        )

    # Basic E.164 length sanity check (max 15 digits after the +).
    if not (1 <= len(e164) - 1 <= 15):
        raise ValueError("phone number %r is not valid E.164 length" % raw)

    return {"e164": e164}

